/**
 * Generate Chatwoot firewall config (cloud-only).
 *
 * Data source: https://www.chatwoot.com/developers/api/
 *
 * Chatwoot uses a custom api_access_token header for authentication.
 * Token format: alphanumeric string, ~20-30 chars, no fixed prefix.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://www.chatwoot.com/developers/api/";
// Format: base58 string, 24 chars (SecureRandom.base58(24))
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSaf";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Chatwoot API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:chatwoot",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const chatwootFirewall = {",
    '  name: "chatwoot",',
    '  description: "Chatwoot API",',
    "  placeholders: {",
    `    CHATWOOT_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://app.chatwoot.com",',
    "      auth: {",
    "        headers: {",
    '          api_access_token: "${{ secrets.CHATWOOT_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Chatwoot firewall config...");
  const ts = generateTypeScript();
  writeOutput("chatwoot", ts, import.meta.dirname);
}
